-- Stored Procedure to Clone Invoice Records\nCREATE PROCEDURE spc_FTR_Clone_Invoice\n    @COMPANIA VARCHAR(2),\n    @IDSEDE VARCHAR(5),\n    @N_FACTURA VARCHAR(16)\nAS\nBEGIN\n    -- Logic to clone FTR/FTRD records\n    -- Insert your cloning logic here following the business rules\n    -- Sample implementation\n    INSERT INTO FTR (COMPANIA, IDSEDE, N_FACTURA)\n    SELECT @COMPANIA, @IDSEDE, NEW_INVOICE_NUMBER\n    WHERE N_FACTURA = @N_FACTURA;\n    -- Additional cloning logic for FTRD records\nEND;\n\n-- Stored Procedure to Assign New Invoice Number After Cloning\nCREATE PROCEDURE spc_FTR_Assign_N_Factura_Clone\n    @N_FACTURA_CLONE VARCHAR(16),\n    @COMPANIA VARCHAR(2)\nAS\nBEGIN\n    -- Logic to assign new invoice number based on cloning process\n    UPDATE FTR\n    SET N_FACTURA = @N_FACTURA_CLONE\n    WHERE COMPANIA = @COMPANIA;\nEND;